class Solution {
public:
    int minEatingSpeed(vector<int>& piles, int h) {
        sort(piles.begin(),piles.end());
        int start = piles[0];
        int end = piles[piles.size()-1];
        int mid = start + (end - start) / 2;
        int guess = 1;
        while(guess){
            mid = start + ((end-start) / 2);
            guess = test(piles, mid, h, end, start);
            if(guess <= -1)
                end = mid;
            else 
                start = mid +1;
        }
        guess = test(piles, mid-1, h, end, start);
        while(guess == 0){
            mid--;
            guess = test(piles, mid-1, h, end, start);

        }

        return mid;
    }
private: 
    int test(vector<int> piles, int mid, int h, int end, int start){
        int turns = 0;
        for(auto i : piles){
            turns += ceil(1.0 * i /mid);
        }
        return turns - h;
}

};

class Solution {
public:
    int minEatingSpeed(vector<int>& piles, int h) {
        int start = 1;
        int end = *max_element(piles.begin(), piles.end());
        int mid = start + (end - start) / 2;
        int guess = 1;

        while(start < end){
            mid = start + ((end-start) / 2);
            if(test(piles, mid, h)){
                end = mid;
            }
            else{
                start = mid +1;
            }
        }
        return start;

    }
private: 
    bool test(vector<int> piles, int k, int h){
        int turns = 0;
        for(auto i : piles){
            turns += (i + k - 1) / k;
        }
        if(turns > h){
            return false;
        }
        return true;
}

};
